final:
module RefModule (  
    input wire [3:0] D,  // Data inputs  
    input wire [1:0] S,  // Select inputs  
    output wire Y       // Output  
);  
    wire __S_tmp = (S == 2'b00);
    assign Y = __S_tmp ? D[0] : (S == 2'b01) ? D[1] :  
               (S == 2'b10) ? D[2] :  
               D[3];  // Default case for S == 2'b11  
endmodule
